import{_ as e,c as t,o as a,d as r}from"./app.b3d21fca.js";var n="/image_meeting_big1920x1080.jpg";const f=JSON.parse('{"title":"Det h\xE4r \xE4r Prodikt","description":"","frontmatter":{},"headers":[{"level":2,"title":"Klimatdeklarera i Prodikt","slug":"klimatdeklarera-i-prodikt"}],"relativePath":"index.md"}'),i={name:"index.md"},o=r('<h1 id="det-har-ar-prodikt" tabindex="-1">Det h\xE4r \xE4r Prodikt <a class="header-anchor" href="#det-har-ar-prodikt" aria-hidden="true">#</a></h1><p>Att enkelt kunna ber\xE4kna och veta exakt vilken klimatp\xE5verkan en byggnad har inte varit sj\xE4lvklart. Med <a href="https://app.prodikt.com/" target="_blank" rel="noopener noreferrer">Prodikt</a> s\xE5 har man kontroll under hela byggprocessen. Fr\xE5n tidigt skede med generisk data, till inbyggda material i en f\xE4rdig byggnad.</p><p>I Prodikt Docs s\xE5 hittar du allt du beh\xF6ver f\xF6r att komma ig\xE5ng med att f\xF6renkla ditt arbete och spara massor av tid. Du hittar all dokumentation i sidomenyn, d\xE4r du \xE4ven kan s\xF6ka efter information.</p><p>Om du inte hittar det du beh\xF6ver eller har f\xF6rslag p\xE5 f\xF6rb\xE4ttringar. <a href="https://app.prodikt.com/#/main/contact" target="_blank" rel="noopener noreferrer">Kontakta oss!</a></p><p><img src="'+n+'" alt="Project team in Prodikt"></p><h2 id="klimatdeklarera-i-prodikt" tabindex="-1">Klimatdeklarera i Prodikt <a class="header-anchor" href="#klimatdeklarera-i-prodikt" aria-hidden="true">#</a></h2><p><em>Lagen om klimatdeklarationer f\xF6r byggnader b\xF6rjade g\xE4lla den 1 januari 2022. Lagen ber\xF6r nya byggnader d\xE4r bygglov s\xF6ks fr\xE5n och med det datumet, och syftet \xE4r att minska klimatp\xE5verkan fr\xE5n byggskedet. Den nya lagen inneb\xE4r att byggherren ska redovisa den klimatp\xE5verkan som uppst\xE5r under byggskedet i en s\xE5 kallad klimatdeklaration som ska registreras hos Boverket i Boverkets register f\xF6r klimatdeklarationer.</em></p><p><strong>F\xF6r att kraftfullt minska koldioxidutsl\xE4ppen fr\xE5n bygg- och fastighetsbranschen finns ett stort behov av att enkelt m\xE4ta klimatp\xE5verkan fr\xE5n material som anv\xE4nds vid byggnationer. Dessutom finns det s\xE5ledes nu ocks\xE5 ett akut behov av verktyg som kan hantera och skapa klimatdeklarationer f\xF6r inregistrering hos Boverket.</strong></p><p><strong>Prodikt</strong> \u2013 en h\xE5llbarhetsplattorm f\xF6r produkter (byggmaterial och m\xF6bler) och projekt har funnits fullt tillg\xE4nglig sedan maj, 2021 och nu kommer en kraftfull och vital uppgradering som kommer att betydligt underl\xE4tta f\xF6r byggbranschens ber\xF6rda akt\xF6rer. M\xF6jligheten att klimatdeklarera kommer i samband med den st\xF6rsta uppdateringen hittills f\xF6r Prodikt, d\xE4r bland andra team-funktion och att arbeta med importerade BIM-filer finns.</p><p>Viljan av att minska klimatavtrycket fr\xE5n branschen har \xF6kat de senaste \xE5ren. Det \xE4r mycket positivt. Nu kommer det d\xE5 ett lagkrav och ett regelverk som pekar ut riktningen ocks\xE5 officiellt. D\xE5 kr\xE4vs det ett konkret och pedagogiskt verktyg. Den nyutvecklade digitala plattformen Prodikt - <a href="http://www.prodikt.com" target="_blank" rel="noopener noreferrer">www.prodikt.com</a>, g\xF6r det m\xF6jligt att p\xE5 ett enkelt s\xE4tt f\xE5 veta olika byggmaterials h\xE5llbarhetsprestanda samt att skapa en klimatdeklaration med h\xF6g kvalitet p\xE5 ett enkelt s\xE4tt.</p><p><em><strong>F\xF6rdelar med att klimatdeklarera i just Prodikt</strong></em></p><ul><li><em>Enkelt och pedagogiskt - passar b\xE5de specialisten och nyb\xF6rjaren</em></li><li><em>Helt unik informationskvalitet - m\xF6jlighet till uppf\xF6ljning och interna m\xE5lv\xE4rden</em></li><li><em>Precisa ber\xE4kningar - b\xE5de EPD*-specifika och generiska v\xE4rden</em></li><li><em>Projektanpassad - st\xF6der projektprocessen vad g\xE4ller import av till exempel kalkylfiler, BIM-modeller och Team-funktion</em></li></ul>',12),l=[o];function d(k,s,m,p,g,h){return a(),t("div",null,l)}var b=e(i,[["render",d]]);export{f as __pageData,b as default};
